function simF(){const p=[{sub200:5,low:12,mid:45,high:28,vhigh:10,peak:1800,vol:72},{sub200:18,low:35,mid:30,high:12,vhigh:5,peak:420,vol:65}];const pr=p[Math.floor(Math.random()*p.length)];const n=()=>Math.floor(Math.random()*8-4);return {bands:{sub200:Math.max(0,pr.sub200+n()),low:Math.max(0,pr.low+n()),mid:Math.max(0,pr.mid+n()),high:Math.max(0,pr.high+n()),vhigh:Math.max(0,pr.vhigh+n())},peakFreq:pr.peak+n()*15,volume:Math.max(10,pr.vol+n()*2)};}

async function callAI(dog,ctx,body,lib,mode){
  const libStr=lib.slice(0,8).map(h=>`${h.category}(${h.confidence}%)${h.correction?" CORRIGÉ→"+h.correctionEmotion:h.validated?" ✓":""}`).join("; ");
  const prompt=`Tu es WOUF, interprète canin IA expert. Réponds en JSON strict.\nCHIEN: ${dog.name}|${dog.sex||"?"}|Race:${dog.breed||dog.breedMode||"?"}|Gabarit:${dog.size||"?"}|Stérilisé:${dog.neutered||"?"}\nPersonnalité: ${dog.personality?.join(",")||"?"} | Déclencheurs: ${dog.triggers?.join(",")||"?"}\nEnv: ${dog.housing||"?"} seul:${dog.alone||"?"} animaux:${dog.otherAnimals||"?"}\nSanté: ${dog.healthSigns?.join(",")||"RAS"}\nMode: ${mode==="precise"?"Précis 7Q":"Rapide 3Q"}\nCONTEXTE: ${Object.keys(ctx).filter(k=>ctx[k]).join(", ")||"?"}\nBODY: ${Object.entries(body).map(([k,v])=>k+":"+v).join(" | ")||"?"}\nHISTORIQUE(${lib.length}): ${libStr||"Aucun"}\n→ JSON: {"hypotheses":[{"category":"Nom","emoji":"e","confidence":55,"color":"#hex","explanation":"2 phrases FR","actions":["conseil1","conseil2","conseil3"],"isRedFlag":false}],"cartography_note":"string|null","recurring_pattern":"string|null","advice":"string|null"}\n3 hypothèses ~100%. Si douleur → RED FLAG+vétérinaire. Si historique>10 scans validés, donne un conseil personnalisé dans "advice".`;
  try{const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});const d=await r.json();const t=d.content?.map(b=>b.type==="text"?b.text:"").join("")||"";return JSON.parse(t.replace(/```json|```/g,"").trim());}catch(e){return null;}
}

// ── UI ─────────────────────────────────────────────────────
function WO({items,selected,onSelect,multi,selList=[],onTog}){
  const[sh,setSh]=useState(false);const[v,setV]=useState("");
  const ok=()=>{if(v.trim()){multi?onTog(v.trim()):onSelect(v.trim());setV("");setSh(false);}};
  return (<div style={{display:"flex",flexWrap:"wrap",gap:5}}>
    {items.map(i=><button key={i} onClick={()=>multi?onTog(i):onSelect(i)} style={(multi?selList.includes(i):selected===i)?{padding:"7px 12px",borderRadius:16,background:"var(--pG2)",border:"2px solid var(--p50)",fontSize:12,color:"var(--p)",cursor:"pointer",fontFamily:FB,fontWeight:700,whiteSpace:"nowrap"}:{padding:"7px 12px",borderRadius:16,background:"var(--bg2)",border:"1px solid var(--bd)",fontSize:12,color:"var(--tx)",cursor:"pointer",fontFamily:FB,whiteSpace:"nowrap"}}>{i}</button>)}
    <button onClick={()=>setSh(!sh)} style={{padding:"7px 12px",borderRadius:16,background:"var(--bg2)",border:"1px dashed var(--td)",fontSize:12,color:"var(--ts)",cursor:"pointer",fontFamily:FB}}>+ Autre</button>
    {sh&&<div style={{width:"100%",display:"flex",gap:5,marginTop:3}}>
      <input value={v} onChange={e=>setV(e.target.value)} onKeyDown={e=>e.key==="Enter"&&ok()} placeholder="Précisez..." style={{flex:1,padding:"8px 10px",borderRadius:8,border:"2px solid var(--bd)",background:"var(--bg2)",color:"var(--tx)",fontSize:13,outline:"none",fontFamily:FB}} autoFocus/>
      <button onClick={ok} style={{padding:"8px 14px",borderRadius:8,background:"var(--p)",border:"none",color:"var(--bg)",fontWeight:700,cursor:"pointer",fontSize:12,fontFamily:F}}>OK</button>
    </div>}
  </div>);
}
function Toggle({value,onChange,label}){return (<div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 0"}}><span style={{fontSize:13,color:"var(--tx)"}}>{label}</span><button onClick={()=>onChange(!value)} style={{width:46,height:24,borderRadius:12,border:"none",background:value?"var(--p)":"var(--td)",cursor:"pointer",position:"relative",transition:".3s"}}><div style={{width:18,height:18,borderRadius:"50%",background:"#FFF",position:"absolute",top:3,left:value?25:3,transition:".3s"}}/></button></div>);}
function XpB({xp}){return (<span style={{fontSize:10,color:"var(--g)",fontWeight:700,fontFamily:F}}>+{xp} XP</span>);}

// ── BREED MULTI-SELECT for mixed ──────────────────────────
function BreedMultiPicker({selected,onToggle}){
  const[q,setQ]=useState("");const[showAdd,setShowAdd]=useState(false);const[nv,setNv]=useState("");
  const filtered=q?BREEDS.filter(b=>b.toLowerCase().includes(q.toLowerCase())):BREEDS;
  const addCustom=()=>{if(nv.trim()){onToggle(nv.trim());setNv("");setShowAdd(false);}};
  return (<div>
    <input value={q} onChange={e=>setQ(e.target.value)} placeholder="🔍 Rechercher une race…" style={{width:"100%",padding:"10px 12px",borderRadius:8,border:"2px solid var(--bd)",background:"var(--bg2)",color:"var(--tx)",fontSize:13,outline:"none",fontFamily:FB,marginBottom:6,boxSizing:"border-box"}}/>
    <div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:6}}>{selected.map(b=><span key={b} onClick={()=>onToggle(b)} style={{padding:"5px 10px",borderRadius:14,background:"var(--pG2)",border:"2px solid var(--p50)",fontSize:11,color:"var(--p)",fontWeight:700,cursor:"pointer"}}>✕ {b}</span>)}</div>
    <div style={{maxHeight:160,overflowY:"auto"}}>{filtered.slice(0,20).map(b=><button key={b} onClick={()=>onToggle(b)} style={{display:"block",width:"100%",padding:"8px 12px",textAlign:"left",background:selected.includes(b)?"var(--pG)":"transparent",border:selected.includes(b)?"1px solid var(--p40)":"1px solid var(--bd)",borderRadius:8,marginBottom:2,fontSize:12,color:selected.includes(b)?"var(--p)":"var(--tx)",fontWeight:selected.includes(b)?700:400,cursor:"pointer",fontFamily:FB}}>{selected.includes(b)?"✓ ":""}{b}</button>)}</div>
    <button onClick={()=>setShowAdd(!showAdd)} style={{width:"100%",padding:"8px 12px",borderRadius:8,border:"1px dashed var(--td)",background:"transparent",color:"var(--ts)",fontSize:11,cursor:"pointer",marginTop:4}}>+ Race non listée</button>
    {showAdd&&<div style={{display:"flex",gap:4,marginTop:4}}><input value={nv} onChange={e=>setNv(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addCustom()} placeholder="Quelle race ?" style={{flex:1,padding:"8px 10px",borderRadius:8,border:"2px solid var(--bd)",background:"var(--bg2)",color:"var(--tx)",fontSize:12,outline:"none",fontFamily:FB}}/><button onClick={addCustom} style={{padding:"8px 12px",borderRadius:8,background:"var(--p)",border:"none",color:"var(--bg)",fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:F}}>Ajouter</button></div>}
  </div>);
}

